using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient and ILogger
/// from DI automatically; they never appear in the tool schema.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Fetch a user by ID from the REST API.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID to look up")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var json = await httpClient.GetStringAsync($"/users/{userId}", cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts to this user ID (omit for all posts)")] int? userId = null,
        [Description("Maximum number of posts to return")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId.Value}" : "/posts";
        logger.LogInformation("Listing posts from {Url}", url);
        var json = await httpClient.GetStringAsync(url, cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var items = doc.RootElement.EnumerateArray().Take(limit);
        return JsonSerializer.Serialize(items, JsonOptions);
    }

    [McpServerTool, Description("Create a new post via the REST API.")]
    public async Task<string> CreatePost(
        [Description("User ID of the post author")] int userId,
        [Description("Post title")] string title,
        [Description("Post body text")] string body,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating post for user {UserId}", userId);
        var payload = new { userId, title, body };
        var response = await httpClient.PostAsJsonAsync("/posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    private static string FormatJson(string json)
    {
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc.RootElement, JsonOptions);
    }
}

